const listUsage = `-- name: ListUsage :many
SELECT u.id, u.session_id, u.provider_id, u.model,
       u.prompt_tokens, u.completion_tokens, u.total_tokens,
       u.latency_ms, u.status_code, u.error_message, u.request_path,
       u.created_at,
       p.name AS provider_name
FROM llm_usage_log u
JOIN llm_providers p ON p.id = u.provider_id
WHERE ($1::BIGINT IS NULL OR u.provider_id = $1)
  AND ($2::TIMESTAMPTZ IS NULL OR u.created_at >= $2)
ORDER BY u.created_at DESC
LIMIT $4
OFFSET $3
`

type ListUsageParams struct {
	ProviderID pgtype.Int8
	Since      pgtype.Timestamptz
	Off        int32
	Lim        int32
}

type ListUsageRow struct {
	ID               int64
	SessionID        pgtype.Int8
	ProviderID       int64
	Model            string
	PromptTokens     int32
	CompletionTokens int32
	TotalTokens      int32
	LatencyMs        int32
	StatusCode       int32
	ErrorMessage     string
	RequestPath      string
	CreatedAt        pgtype.Timestamptz
	ProviderName     string
}

// Explicit column list excludes request_body/response_body so the list
// query stays fast — the detail endpoint (GetUsageByID) carries the large
// body columns on a single row.
func (q *Queries) ListUsage(ctx context.Context, arg ListUsageParams) ([]ListUsageRow, error) {
	rows, err := q.db.Query(ctx, listUsage,
		arg.ProviderID,
		arg.Since,
		arg.Off,
		arg.Lim,
	)
	if err != nil {
		return nil, err
	}
	defer rows.Close()
	items := []ListUsageRow{}
	for rows.Next() {
		var i ListUsageRow
		if err := rows.Scan(
			&i.ID,
			&i.SessionID,
			&i.ProviderID,
			&i.Model,
			&i.PromptTokens,
			&i.CompletionTokens,
			&i.TotalTokens,
			&i.LatencyMs,
			&i.StatusCode,
			&i.ErrorMessage,
			&i.RequestPath,
			&i.CreatedAt,
			&i.ProviderName,
		); err != nil {
			return nil, err
		}
		items = append(items, i)
	}
	if err := rows.Err(); err != nil {
		return nil, err
	}
	return items, nil
}

