const replaceMembers = `-- name: ReplaceMembers :exec

DELETE FROM llm_model_group_members WHERE group_id = $1
`

// ---- model group members ----
// Delete all existing members for the group, then insert the new list.
// Callers must wrap both in a transaction.
func (q *Queries) ReplaceMembers(ctx context.Context, groupID int64) error {
	_, err := q.db.Exec(ctx, replaceMembers, groupID)
	return err
}

