const updateMemberHealth = `-- name: UpdateMemberHealth :execrows
UPDATE llm_model_group_members SET
    manual_disabled     = COALESCE($1, manual_disabled),
    auto_disabled_until = CASE WHEN $2::TIMESTAMPTZ IS NOT NULL
                               THEN $2
                               WHEN $3::BOOLEAN
                               THEN NULL
                               ELSE auto_disabled_until END,
    backoff_step        = COALESCE($4, backoff_step),
    last_failure_at     = COALESCE($5, last_failure_at),
    last_failure_msg    = COALESCE($6, last_failure_msg),
    last_success_at     = COALESCE($7, last_success_at),
    last_checked_at     = COALESCE($8, last_checked_at),
    updated_at          = NOW()
WHERE id = $9
`

type UpdateMemberHealthParams struct {
	ManualDisabled        pgtype.Bool
	AutoDisabledUntil     pgtype.Timestamptz
	AutoDisabledUntilNull pgtype.Bool
	BackoffStep           pgtype.Int4
	LastFailureAt         pgtype.Timestamptz
	LastFailureMsg        pgtype.Text
	LastSuccessAt         pgtype.Timestamptz
	LastCheckedAt         pgtype.Timestamptz
	ID                    int64
}

// Atomically update health fields. Each field is only touched when its
// corresponding parameter is non-null (sqlc.narg). This single-statement
// pattern avoids a read-then-write race on backoff_step.
func (q *Queries) UpdateMemberHealth(ctx context.Context, arg UpdateMemberHealthParams) (int64, error) {
	result, err := q.db.Exec(ctx, updateMemberHealth,
		arg.ManualDisabled,
		arg.AutoDisabledUntil,
		arg.AutoDisabledUntilNull,
		arg.BackoffStep,
		arg.LastFailureAt,
		arg.LastFailureMsg,
		arg.LastSuccessAt,
		arg.LastCheckedAt,
		arg.ID,
	)
	if err != nil {
		return 0, err
	}
	return result.RowsAffected(), nil
}

